)
INSERT INTO public.accounts_payable (supplier_id, category_id, description, document_number, issue_date, due_date, amount, currency_code, status, notes, metadata, source_system, external_ref)
SELECT s.id, cat.id, src.description, src.document_number, LEAST(src.issue_date::date, src.due_date::date), GREATEST(src.issue_date::date, src.due_date::date), src.amount::numeric(14,2), 'BRL', src.status::payable_status, 'Imported from Bling contas_pagar', src.metadata, 'bling', src.external_ref FROM src JOIN public.suppliers s ON s.source_system = 'bling' AND s.external_ref = src.supplier_external_ref CROSS JOIN cat ON CONFLICT (source_system, external_ref) DO UPDATE SET supplier_id = EXCLUDED.supplier_id, category_id = EXCLUDED.category_id, description = EXCLUDED.description, document_number = EXCLUDED.document_number, issue_date = EXCLUDED.issue_date, due_date = EXCLUDED.due_date, amount = EXCLUDED.amount, status = EXCLUDED.status, metadata = COALESCE(public.accounts_payable.metadata, '{}'::jsonb) || EXCLUDED.metadata, updated_at = now();

